const numero: number = 7;

for (let i: number = 1; i <= 10; i++) {
  console.log(`${numero} x ${i} = ${numero * i}`);
}

for (let linha: number = 1; linha <= 5; linha++) {
  let texto: string = "";
  for (let col: number = 1; col <= linha; col++) {
    texto += "*";
  }
  console.log(texto);
}

for (let i: number = 1; i <= 20; i++) {
  if (i % 3 === 0 && i % 5 === 0) {
    console.log("FizzBuzz");
  } else if (i % 3 === 0) {
    console.log("Fizz");
  } else if (i % 5 === 0) {
    console.log("Buzz");
  } else {
    console.log(i);
  }
}
